import sys
from collections import defaultdict

class Solution:
    def solve(self, edges: list[list[int]], V: int) -> None:
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        visited = [False] * V
        disc = [float('inf')] * V
        low = [float('inf')] * V
        parent = [-1] * V
        ap = [False] * V
        time = 0

        def dfs(v):
            nonlocal time
            visited[v] = True
            disc[v] = time
            low[v] = time
            time += 1
            children = 0
            for neighbor in graph[v]:
                if not visited[neighbor]:
                    parent[neighbor] = v
                    children += 1
                    dfs(neighbor)
                    low[v] = min(low[v], low[neighbor])
                    if parent[v] == -1 and children > 1:
                        ap[v] = True
                    if parent[v] != -1 and low[neighbor] >= disc[v]:
                        ap[v] = True
                elif neighbor != parent[v]:
                    low[v] = min(low[v], disc[neighbor])

        for i in range(V):
            if not visited[i]:
                parent[i] = -1
                dfs(i)

        for i in range(V):
            if ap[i]:
                print(i)

if __name__ == '__main__':
    try:
        V, E = map(int, sys.stdin.readline().split())
        edges = [list(map(int, sys.stdin.readline().split())) for _ in range(E)]
    except Exception as e:
        sys.exit(0)
    sol = Solution()
    sol.solve(edges, V)

