#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void solve(vector<vector<int>>& edges, int V) {
        unordered_map<int, vector<int>> graph;
        for (const auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            graph[edge[1]].push_back(edge[0]);
        }

        vector<bool> visited(V, false);
        vector<int> disc(V, INT_MAX);
        vector<int> low(V, INT_MAX);
        vector<int> parent(V, -1);
        vector<bool> ap(V, false);
        int time = 0;

        function<void(int)> dfs = [&](int v) {
            visited[v] = true;
            disc[v] = time;
            low[v] = time;
            time++;
            int children = 0;
            for (int neighbor : graph[v]) {
                if (!visited[neighbor]) {
                    parent[neighbor] = v;
                    children++;
                    dfs(neighbor);
                    low[v] = min(low[v], low[neighbor]);
                    if (parent[v] == -1 && children > 1) {
                        ap[v] = true;
                    }
                    if (parent[v] != -1 && low[neighbor] >= disc[v]) {
                        ap[v] = true;
                    }
                } else if (neighbor != parent[v]) {
                    low[v] = min(low[v], disc[neighbor]);
                }
            }
        };

        for (int i = 0; i < V; i++) {
            if (!visited[i]) {
                parent[i] = -1;
                dfs(i);
            }
        }

        for (int i = 0; i < V; i++) {
            if (ap[i]) {
                cout << i << '\n';
            }
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (int i = 0; i < E; i++) {
        if (!(cin >> edges[i][0] >> edges[i][1])) return 0;
    }
    Solution sol;
    sol.solve(edges, V);
    return 0;
}
